// Nó: Preparar SQL

const device_id = msg.payload.device_id;
const ruido_dbfs = msg.payload.ruido_dbfs;
const temperatura = msg.payload.temperatura;
const umidade = msg.payload.umidade;
const received_timestamp = msg.payload.timestamp; 

// Verificação de segurança: Se os dados estiverem chegando, esta checagem não deve parar o fluxo.
if (device_id === undefined || ruido_dbfs === undefined || received_timestamp === undefined
    || temperatura === undefined || umidade === undefined) {
    node.warn("Um ou mais campos (device_id, ruido_dbfs, timestamp) estão faltando no payload. Abortando inserção.");
    return null; 
}

// 1. Comando SQL (msg.topic)
// Confirme que o nome da tabela e das colunas estão corretos: leituras_sono.device_id
msg.topic = "INSERT INTO leituras_sono (device_id, ruido_dbfs, temperatura, umidade, timestamp) VALUES ('"+device_id+"',"+ruido_dbfs+", "+temperatura+", "+umidade+", "+received_timestamp+")";

// 2. Valores para inserção (msg.payload)
// ESTA ORDEM É CRÍTICA! Deve corresponder aos '?' e à ordem das colunas acima.
msg.payload = [device_id, ruido_dbfs, temperatura, umidade, received_timestamp];

// 3. Dados para resposta final
msg.dados_armazenados = {
    device_id: device_id,
    ruido_dbfs: ruido_dbfs,
    temperatura: temperatura,
    umidade: umidade,
    timestamp: received_timestamp 
};

return msg;

// O payload do nó SQLite agora é algo como { changes: 1, lastID: 5 }
const sql_response = msg.payload;

// Os dados originais que você armazenou estão em msg.dados_armazenados
const dados_armazenados = msg.dados_armazenados;

// Prepare o objeto de resposta para o cliente
msg.payload = {
    status: "sucesso",
    mensagem: "Dados do sensor armazenados com sucesso.",
    id_inserido: sql_response.lastID, // O ID da linha inserida
    dados_recebidos: dados_armazenados
};

// Define o código de status HTTP (201 Created é uma boa prática para inserções)
msg.statusCode = 201;

return msg;
